#!/bin/sh
# Server Monitor - self-extracting installer with uv-managed Python
# Usage: ./server-monitor.sh [extract-dir]

set -e

if [ ! -f "$0" ]; then
    log "ERROR: Cannot run via pipe. Download first:"
    log "  curl -fsSL -o server-monitor.sh https://github.com/2099742859-lgtm/server-monitor/releases/download/v1/server-monitor.sh"
    log "  bash server-monitor.sh"
    exit 1
fi

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
DEST_DIR="${1:-$SCRIPT_DIR/server-monitor}"

log() {
    echo "[server-monitor] $1"
}

log "Checking uv..."
if ! command -v uv >/dev/null 2>&1; then
    log "uv not found. Installing uv..."
    if command -v curl >/dev/null 2>&1; then
        curl -LsSf https://astral.sh/uv/install.sh | sh
    elif command -v wget >/dev/null 2>&1; then
        wget -qO- https://astral.sh/uv/install.sh | sh
    else
        log "ERROR: Need curl or wget to install uv."
        exit 1
    fi
    export PATH="$HOME/.local/bin:$HOME/.cargo/bin:$PATH"
fi

log "Using uv: $(uv --version)"

log "Installing Python 3.11 via uv..."
uv python install 3.11

log "Extracting archive..."
ARCHIVE_START=$(awk '/^__ARCHIVE_BELOW__/ {print NR+1; exit 0;}' "$0")
mkdir -p "$DEST_DIR"
tail -n +"$ARCHIVE_START" "$0" | base64 -d | tar -xzf - -C "$DEST_DIR"
log "Extracted to: $DEST_DIR"

cd "$DEST_DIR"

log "Creating virtual environment..."
uv venv --clear

log "Installing dependencies..."
uv pip install -r requirements.txt

log "Starting server at http://0.0.0.0:5000"
exec ./.venv/bin/python app.py

exit 0
__ARCHIVE_BELOW__
